import type { VisitorContextType } from '../types';

export class VisitorContextError extends Error {
    constructor(message: string) {
        super(message);
        this.name = 'VisitorContextError';
    }

    static assert(parentType: VisitorContextType, childType: VisitorContextType) {
        if (
            (parentType === 'component' && childType !== 'region') ||
            (parentType === 'page' && childType !== 'region') ||
            (parentType === 'region' && childType !== 'component')
        ) {
            throw new VisitorContextError(
                `Invalid child context type ${childType} for parent context type ${parentType}`
            );
        }
    }
}
