export class RequiredError extends Error {
    constructor(message: string) {
        super(message);
        this.name = 'RequiredError';
    }

    static assert<TValue>(
        value: TValue,
        message: string,
        isEmpty: (value: TValue) => boolean = (v) => v == null
    ): asserts value is NonNullable<TValue> {
        if (isEmpty(value)) {
            throw new RequiredError(message);
        }
    }
}
